const router=require('express').Router(); const db=require('../config/db'); const asyncHandler=require('../utils/asyncHandler'); const { addToCart }=require('../utils/cart');
router.get('/', asyncHandler(async(req,res)=>{ const bundles=(await db.query('SELECT * FROM productbundles WHERE COALESCE(isactive,true)=true ORDER BY displayorder NULLS LAST, createdat DESC NULLS LAST').catch(()=>({rows:[]}))).rows; res.render('bundle/index',{title:'Combo ưu đãi',bundles}); }));
router.get('/:id', asyncHandler(async(req,res)=>{ const bundle=await db.one('SELECT * FROM productbundles WHERE bundleid=$1',[req.params.id]); const items=(await db.query('SELECT bi.*, p.productname,p.price,p.imageurl FROM productbundleitems bi JOIN products p ON p.productid=bi.productid WHERE bi.bundleid=$1',[req.params.id]).catch(()=>({rows:[]}))).rows; res.render('bundle/details',{title:bundle?.bundlename||'Combo',bundle,items}); }));
router.post('/:id/add', asyncHandler(async(req,res)=>{ const items=(await db.query('SELECT bi.quantity,p.* FROM productbundleitems bi JOIN products p ON p.productid=bi.productid WHERE bi.bundleid=$1',[req.params.id])).rows; items.forEach(i=>addToCart(req,{...i,finalprice:i.price},i.quantity)); req.flash('success','Đã thêm combo vào giỏ hàng.'); res.redirect('/cart'); }));
module.exports=router;
